 99→template<typename CPU, typename PLATFORM>
100→class simulator : sc_core::sc_module
101→{
102→  using PeTargetType = typename PLATFORM::PeTargetType;
103→
104→public:
105→  CPU cpu;
106→  PLATFORM platform;
107→
108→private:
109→  // debug
110→  jtag_dtm& dtm;
111→  bool dtm_debug = false;
112→
113→  // control signals
114→  sc_core::sc_signal<bool> resetn{};
115→  sc_core::sc_signal<vlpin<CPU::NDS_VALEN>> reset_vector{"reset_vector", 0};
116→
117→  // trace
118→#ifdef VSIMDEBUG
119→  std::unique_ptr<VerilatedVcdSc> trace_file{};
120→#endif // VSIMDEBUG
121→
122→  std::string trace_filename;
123→
124→  using xlen_t = std::conditional_t<CPU::NDS_XLEN <= 32, uint32_t, uint64_t>;
125→
126→public:
127→  simulator(const sc_core::sc_module_name& name)
128→      : sc_core::sc_module{name}, dtm(platform.dtm)
129→  {
130→    // bind cpu to platform
131→    cpu.bind(platform.clk, this->resetn, this->reset_vector,
132→             platform.dmi_signals);
133→
134→    platform.interconnect.bind_initiator(cpu.mem_bfm.isckt);
135→
136→    if constexpr (requires { cpu.mmio_bfm; })
137→      platform.interconnect.bind_initiator(cpu.mmio_bfm.isckt);
138→
139→    if constexpr (requires { cpu.hvm_bfm; }) {
140→      platform.interconnect.bind_target(
141→        cpu.hvm_bfm.tsckt,
142→        {CPU::NDS_HVM_BASE,
143→         CPU::NDS_HVM_BASE + CPU::NDS_HVM_SIZE_KB * 0x1000 - 1});
144→      platform.custom_master.hvm_base = CPU::NDS_HVM_BASE;
145→    }
146→
147→    if constexpr (requires { cpu.slv_bfm; }) {
148→      platform.interconnect.bind_target(cpu.slv_bfm.tsckt,
149→                                        {HART0_ILM_BASE, HART0_DLM_END});
150→      platform.custom_master.ilm_base = HART0_ILM_BASE;
151→      platform.custom_master.dlm_base = HART0_DLM_BASE;
152→    }
153→  }
154→
155→  ~simulator() { close_trace(); }
156→
157→  void init_debug_port(const uint16_t port = 9104)
158→  {
159→    // TODO: ERROR check?
160→    dtm_debug = true;
161→    dtm.init_port(port);
162→    spdlog::info("waiting for debugger connection");
163→    // dtm.try_accept_socket();
164→  }
165→
166→  void load_elf(const std::string& path)
167→  {
168→    const auto elf = LIEF::ELF::Parser::parse(path);
169→
170→    read_elf_into_memory(*elf, xlen_t{0}, platform.main_memory.data);
171→    reset_vector.write(elf->entrypoint());
172→    spdlog::info("Setting reset vector to {:#x}", elf->entrypoint());
173→  }
174→
175→  void reset()
176→  {
177→    this->resetn.write(false);
178→    this->run(1);
179→    this->resetn.write(true);
180→  }
181→
182→  int run(const uint64_t count = std::numeric_limits<uint64_t>::max())
183→  {
184→    auto sa = memzeroed<struct sigaction>();
185→    sa.sa_handler = sigint_handler;
186→    sigemptyset(&sa.sa_mask);
187→
188→    auto oact = memzeroed<struct sigaction>();
189→    if (sigaction(SIGINT, &sa, &oact) == -1)
190→      perror("sigaction");
191→
192→    const auto restore_sigint = std::experimental::scope_exit{[&] {
193→      if (sigaction(SIGINT, &oact, nullptr) == -1)
194→        perror("sigaction");
195→    }};
196→
197→    // wait for debugger connections
198→    while (dtm_debug && !dtm.is_connected()) {
199→      dtm.try_accept_socket();
200→      if (ctrlc != 0) {
201→        return 130;
202→      }
203→      sleep(1);
204→    }
205→
206→    for (auto n = uint64_t{0}; n < count; ++n) {
207→      sc_core::sc_start(platform.clk.period());
208→
209→      if (ctrlc != 0) {
210→        ctrlc = 0;
211→        spdlog::info("Ctrl+C PC: {:x}", get_current_pc());
212→        return 130;
213→      }
214→
215→      if (platform.sim_control.exits >= 0) {
216→        spdlog::info("sim_control: got exit {}, stopping",
217→                     platform.sim_control.exits);
218→        spdlog::info("Exit PC: {:x}", get_current_pc());
219→        return platform.sim_control.exits;
220→      }
221→
222→      if (this->cpu.contextp()->gotFinish())
223→        return 0;
224→
225→      spdlog::trace("PC: {:x}", get_current_pc());
226→    }
227→    return 0;
228→  }
