230→  uint64_t get_current_pc(void)
231→  {
232→    if constexpr (requires { cpu.get_current_pc(); }) {
233→      return cpu.get_current_pc();
234→    }
235→    return std::numeric_limits<uint64_t>::max();
236→  }
