238→  void enable_trace_logging(const std::string& trace_filename)
239→  {
240→    this->trace_filename = trace_filename;
241→
242→#ifdef VSIMDEBUG
243→    if (this->trace_file) {
244→      spdlog::info("Tracing is already enabled.");
245→      return;
246→    }
247→    if constexpr (requires { cpu.trace(this->trace_file.get(), 0); }) {
248→      this->trace_file = std::make_unique<VerilatedVcdSc>();
249→      this->cpu.contextp()->traceEverOn(true);
250→      this->cpu.trace(this->trace_file.get(), 0);
251→      this->trace_file->open(this->trace_filename.c_str());
252→      spdlog::info("Writing traces to {}", this->trace_filename);
253→      return;
254→    }
255→#endif // VSIMDEBUG
256→
257→    spdlog::critical("Tracing is not supported.");
258→    exit(EXIT_FAILURE);
259→  }
