261→  auto get_cycles() -> std::uint64_t
262→  {
263→    const auto time_resolution = sc_core::sc_get_time_resolution();
264→    const auto divider =
265→      platform.clk.period().value() / time_resolution.value();
266→    return sc_core::sc_time_stamp().value() / divider;
267→  }
